        private void postToJs(String callbackId, JSONObject payload) {
            WebView wv = webViewRef.get();
            Activity act = activityRef.get();
            if (wv == null || act == null) return;

            final String cb = callbackId == null ? "" : callbackId;
            final String json = payload != null ? payload.toString() : "{}";
            final String script = "window.HybridNative && window.HybridNative._onNativeCallback && " +
                    "window.HybridNative._onNativeCallback(" + JSONObject.quote(cb) + "," + json + ");";
            act.runOnUiThread(() -> {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
                    wv.evaluateJavascript(script, null);
                } else {
                    wv.loadUrl("javascript:" + script);
                }
            });
        }

